    onHouseholdLeave: () => Promise<void>; 
    onHouseholdDelete: () => Promise<void>; 
    error: string | null;
}> = (props) => {
    const navigate = useNavigate();
    return <SettingsModal onClose={() => navigate(-1)} {...props} />;
};

// 2. Detail Page Component
