import React, { Component, ErrorInfo, ReactNode } from 'react';
import { AlertTriangleIcon } from './Icons';

interface Props {
  children?: ReactNode;
}

interface State {
  hasError: boolean;
  error: Error | null;
}

export class ErrorBoundary extends Component<Props, State> {
  constructor(props: Props) {
    super(props);
    this.state = {
      hasError: false,
      error: null,
    };
  }

  public static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
  }

  private handleReload = () => {
    window.location.reload();
  };

  public render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50 dark:bg-gray-900 p-4 text-center">
          <div className="bg-white dark:bg-gray-800 p-8 rounded-2xl shadow-xl max-w-md w-full border border-gray-100 dark:border-gray-700">
            <div className="flex justify-center mb-6">
                <div className="p-4 bg-red-100 dark:bg-red-900/30 rounded-full">
                    <AlertTriangleIcon className="w-12 h-12 text-red-600 dark:text-red-400" />
                </div>
            </div>
            <h1 className="text-2xl font-bold text-gray-900 dark:text-white mb-2">Ups, etwas ist schiefgelaufen.</h1>
            <p className="text-gray-600 dark:text-gray-400 mb-6 text-sm">
              Die App ist auf einen unerwarteten Fehler gestoßen. Wir haben dies protokolliert.
            </p>

            {/* Optional: Show error message in dev mode only, or simplified for user */}
            {this.state.error && (
                <div className="mb-6 p-3 bg-gray-100 dark:bg-gray-900 rounded text-xs text-left font-mono text-red-500 overflow-auto max-h-32">
                    {this.state.error.toString()}
                </div>
            )}

            <button
              onClick={this.handleReload}
              className="w-full py-3 px-6 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl transition-colors shadow-md"
            >
              App neu laden
            </button>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

export type NutriScore = 'A' | 'B' | 'C' | 'D' | 'E';

export type FoodItemType = 'product' | 'dish' | 'drugstore';

export type GroceryCategory = 
  | 'produce' 
  | 'bakery' 
  | 'meat_fish' 
  | 'dairy_eggs' 
  | 'pantry' 
  | 'frozen' 
  | 'snacks' 
  | 'beverages' 
  | 'household' 
  | 'personal_care' 
  | 'restaurant_food'
  | 'other';

export interface FoodItem {
  id: string;
  user_id: string;
  created_at: string;
  name: string;
  rating: number; // 0 for unrated, 1-5 for star rating
  itemType: FoodItemType;
  isFamilyFavorite?: boolean; // Replaces isPublic for household sharing

  // Inventory
  inventoryQuantity?: number; // Current stock count

  // Common fields
  notes?: string;
  image?: string; // URL to the image in cloud storage
  tags?: string[];
  category?: GroceryCategory; // New field for supermarket sorting

  // Product-specific fields
  nutriScore?: NutriScore;
  calories?: number; // Energy in kcal per 100g/100ml or per serving
  ingredients?: string[];
  allergens?: string[];
  isLactoseFree?: boolean;
  isVegan?: boolean;
  isGlutenFree?: boolean;
  purchaseLocation?: string[]; // e.g., ["Lidl", "Whole Foods"]

  // Dish-specific fields
  restaurantName?: string;
  cuisineType?: string;
  price?: number; // Current/Latest known price
}

// Represents a household that users can join.
export interface Household {
  id: string;
  name: string;
  owner_id: string;
  created_at: string;
  saved_shops?: string[]; // Stores the preferred shops for this household
}

// Represents a distinct shopping list, belonging to a household.
export interface ShoppingList {
  id: string;
  household_id: string;
  name: string;
  created_at: string;
}

// Represents an item on a specific shopping list.
export interface ShoppingListItem {
  id: string;
  list_id: string; // Foreign key to the ShoppingList
  food_item_id: string; // Foreign key to the FoodItem
  added_by_user_id: string;
  checked: boolean;
  created_at: string;
  checked_by_user_id: string | null;
  quantity: number; // The number of this item to buy
}

// Represents a user's public profile information.
export interface UserProfile {
  id: string; // Corresponds to auth.users.id
  display_name: string;
  household_id?: string | null;
}

