export const fetchUserFoodItems = async (userId: string) => {
  const { data, error } = await supabase
    .from('food_items')
    .select('*')
    .eq('user_id', userId)
    .order('created_at', { ascending: false });

  if (error) throw error;
  return (data || []).map(mapDbToFoodItem);
};

export const fetchFamilyFavorites = async () => {
    const { data, error } = await supabase
        .from('food_items')
        .select('*')
        .eq('is_family_favorite', true);

    if (error) throw error;
    return (data || []).map(mapDbToFoodItem);
};

export const createFoodItem = async (item: Omit<FoodItem, 'id' | 'user_id' | 'created_at'>, userId: string, imageUrl?: string) => {
  const payload = mapFoodItemToDbPayload({ ...item, user_id: userId, image_url: imageUrl });

  const { data, error } = await supabase
    .from('food_items')
    .insert(payload)
    .select()
    .single();

  if (error) {
      console.warn("Cascade retry for single item:", error.message);
      const { calories, ...payloadNoCalories } = payload;
      const { data: r1, error: e1 } = await supabase.from('food_items').insert(payloadNoCalories).select().single();
      if (!e1) return mapDbToFoodItem(r1);

      const { category, ...payloadLegacy } = payloadNoCalories;
      const { data: r2, error: e2 } = await supabase.from('food_items').insert(payloadLegacy).select().single();
      if (!e2) return mapDbToFoodItem(r2);
      throw error;
  }
  return mapDbToFoodItem(data);
};

/**
 * Enhanced Bulk Import with Multi-Stage Recovery Strategy
 */
export const createFoodItemsBulk = async (items: (Omit<FoodItem, 'id' | 'user_id' | 'created_at'>)[], userId: string): Promise<FoodItem[]> => {
    if (items.length === 0) return [];

    const basePayloads = items.map(item => mapFoodItemToDbPayload({ ...item, user_id: userId }));

    // Helper for batch attempts
    const attemptBatch = async (payloads: any[]) => {
        const { data, error } = await supabase.from('food_items').insert(payloads).select();
        return { data, error };
    };

    // Stage 1: Full Batch
    let result = await attemptBatch(basePayloads);
    if (!result.error) return (result.data || []).map(mapDbToFoodItem);

    console.warn("Bulk import Stage 1 failed, trying without 'calories'...", result.error.message);

    // Stage 2: Remove 'calories'
    const payloadsNoCalories = basePayloads.map(({ calories, ...rest }) => rest);
    result = await attemptBatch(payloadsNoCalories);
    if (!result.error) return (result.data || []).map(mapDbToFoodItem);

    console.warn("Bulk import Stage 2 failed, trying without 'category'...", result.error.message);

    // Stage 3: Remove 'calories' AND 'category'
    const payloadsLegacy = payloadsNoCalories.map(({ category, ...rest }) => rest);
    result = await attemptBatch(payloadsLegacy);
    if (!result.error) return (result.data || []).map(mapDbToFoodItem);

    // Stage 4: Nuclear Option - Individual Inserts (Slow but guaranteed to save what's possible)
    console.warn("Bulk import Stage 3 failed. Switching to individual resilient inserts...");
    const savedItems: FoodItem[] = [];
    for (const item of items) {
        try {
            const saved = await createFoodItem(item, userId);
            savedItems.push(saved);
        } catch (e) {
            console.error("Failed to save individual item during bulk fallback:", item.name, e);
        }
    }

    if (savedItems.length === 0) throw new Error("Mass import failed completely. Check database connection and schema.");
    return savedItems;
};

export const updateFoodItem = async (id: string, item: Omit<FoodItem, 'id' | 'user_id' | 'created_at'>, userId: string, imageUrl?: string) => {
  const payload = mapFoodItemToDbPayload({ ...item, user_id: userId, image_url: imageUrl });

  const { data, error } = await supabase.from('food_items').update(payload).eq('id', id).select().single();

  if (error) {
      console.warn("Cascade retry for update:", error.message);
      const { calories, ...p1 } = payload;
      const { data: r1, error: e1 } = await supabase.from('food_items').update(p1).eq('id', id).select().single();
      if (!e1) return mapDbToFoodItem(r1);

      const { category, ...p2 } = p1;
      const { data: r2, error: e2 } = await supabase.from('food_items').update(p2).eq('id', id).select().single();
      if (!e2) return mapDbToFoodItem(r2);
      throw error;
  }
  return mapDbToFoodItem(data);
};

export const updateFoodItemInventory = async (id: string, quantity: number) => {
    const { data, error } = await supabase.from('food_items').update({ inventory_quantity: quantity }).eq('id', id).select().single();
    if (error) throw error;
    return mapDbToFoodItem(data);
};

export const deleteFoodItem = async (id: string) => {
  const { error } = await supabase.from('food_items').delete().eq('id', id);
  if (error) throw error;
};

import { useCallback } from 'react';
import { FoodItem } from '../types';
import { User } from '@supabase/supabase-js';
import * as foodItemService from '../services/foodItemService';
import { supabase } from '../services/supabaseClient';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';

const base64ToBlob = (base64: string, mimeType: string): Blob => {
  const byteCharacters = atob(base64.split(',')[1]);
  const byteArrays = [];
  for (let offset = 0; offset < byteCharacters.length; offset += 512) {
    const slice = byteCharacters.slice(offset, offset + 512);
    const byteNumbers = new Array(slice.length);
    for (let i = 0; i < slice.length; i++) { byteNumbers[i] = slice.charCodeAt(i); }
    const byteArray = new Uint8Array(byteNumbers);
    byteArrays.push(byteArray);
  }
  return new Blob(byteArrays, { type: mimeType });
};

// Keys for caching
const KEYS = {
    personal: (userId: string) => ['foodItems', 'personal', userId],
    family: (householdId?: string | null) => ['foodItems', 'family', householdId],
};

export const useFoodData = (user: User | null, householdId?: string | null) => {
  const queryClient = useQueryClient();

  // --- QUERIES (Read) ---

  const { data: foodItems = [], isLoading: isLoadingPersonal, error: errorPersonal } = useQuery({
      queryKey: KEYS.personal(user?.id || ''),
      queryFn: () => foodItemService.fetchUserFoodItems(user!.id),
      enabled: !!user,
      staleTime: 1000 * 60 * 2, // 2 mins
  });

  const { data: familyFoodItems = [], isLoading: isLoadingFamily } = useQuery({
      queryKey: KEYS.family(householdId),
      queryFn: () => foodItemService.fetchFamilyFavorites(),
      enabled: !!householdId,
      staleTime: 1000 * 60 * 2,
  });

  // --- MUTATIONS (Write) ---

  const saveMutation = useMutation({
      mutationFn: async ({ itemData, existingId }: { itemData: Omit<FoodItem, 'id' | 'user_id' | 'created_at'>, existingId?: string }) => {
          if (!user) throw new Error("No user");

          let imageUrl = itemData.image;
          // Handle Image Upload
          if (imageUrl && imageUrl.startsWith('data:image')) {
              const mimeType = imageUrl.match(/data:([a-zA-Z0-9]+\/[a-zA-Z0-9-.+]+).*,.*/)?.[1] || 'image/jpeg';
              const blob = base64ToBlob(imageUrl, mimeType);
              const fileName = `${user.id}/${Date.now()}_${Math.random().toString(36).substring(2, 9)}.jpg`;
              const { error: uploadError } = await supabase.storage.from('food-images').upload(fileName, blob, { contentType: mimeType });
              if (uploadError) throw uploadError;
              const { data: urlData } = supabase.storage.from('food-images').getPublicUrl(fileName);
              imageUrl = urlData.publicUrl;
          }

          if (existingId) {
              return await foodItemService.updateFoodItem(existingId, itemData, user.id, imageUrl);
          } else {
              return await foodItemService.createFoodItem(itemData, user.id, imageUrl);
          }
      },
      onMutate: async ({ itemData, existingId }) => {
          // Cancel outgoing refetches
          await queryClient.cancelQueries({ queryKey: KEYS.personal(user?.id || '') });

          // Snapshot previous value
          const previousItems = queryClient.getQueryData<FoodItem[]>(KEYS.personal(user?.id || ''));

          // Optimistic Update
          queryClient.setQueryData<FoodItem[]>(KEYS.personal(user?.id || ''), (old) => {
              if (!old) return [];
              const optimisticItem = {
                  ...itemData,
                  id: existingId || `temp_${Date.now()}`,
                  user_id: user!.id,
                  created_at: new Date().toISOString(),
                  image: itemData.image // Use base64 temporarily
              } as FoodItem;

              if (existingId) {
                  return old.map(item => item.id === existingId ? { ...item, ...optimisticItem } : item);
              } else {
                  return [optimisticItem, ...old];
              }
          });

          return { previousItems };
      },
      onError: (err, newTodo, context) => {
          console.error("Save failed", err);
          if (context?.previousItems) {
              queryClient.setQueryData(KEYS.personal(user?.id || ''), context.previousItems);
          }
      },
      onSettled: () => {
          queryClient.invalidateQueries({ queryKey: KEYS.personal(user?.id || '') });
          if (householdId) queryClient.invalidateQueries({ queryKey: KEYS.family(householdId) });
      }
  });

  const inventoryMutation = useMutation({
      mutationFn: async ({ id, quantity }: { id: string, quantity: number }) => {
          return await foodItemService.updateFoodItemInventory(id, quantity);
      },
      onMutate: async ({ id, quantity }) => {
          // Identify keys to update
          const personalKey = KEYS.personal(user?.id || '');
          const familyKey = KEYS.family(householdId);

          await queryClient.cancelQueries({ queryKey: personalKey });
          if (householdId) await queryClient.cancelQueries({ queryKey: familyKey });

          const prevPersonal = queryClient.getQueryData<FoodItem[]>(personalKey);
          const prevFamily = householdId ? queryClient.getQueryData<FoodItem[]>(familyKey) : undefined;

          // Optimistic update helper
          const updateCache = (old: FoodItem[] | undefined) => {
              return old ? old.map(item => item.id === id ? { ...item, inventoryQuantity: quantity } : item) : [];
          };

          queryClient.setQueryData<FoodItem[]>(personalKey, updateCache);
          if (householdId) queryClient.setQueryData<FoodItem[]>(familyKey, updateCache);

          return { prevPersonal, prevFamily };
      },
      onError: (err, vars, context) => {
          if (context?.prevPersonal) queryClient.setQueryData(KEYS.personal(user?.id || ''), context.prevPersonal);
          if (context?.prevFamily && householdId) queryClient.setQueryData(KEYS.family(householdId), context.prevFamily);
      },
      onSettled: () => {
          queryClient.invalidateQueries({ queryKey: KEYS.personal(user?.id || '') });
          if (householdId) queryClient.invalidateQueries({ queryKey: KEYS.family(householdId) });
      }
  });

  const deleteMutation = useMutation({
      mutationFn: async (id: string) => {
          await foodItemService.deleteFoodItem(id);
      },
      onMutate: async (id) => {
          await queryClient.cancelQueries({ queryKey: KEYS.personal(user?.id || '') });
          const previousItems = queryClient.getQueryData<FoodItem[]>(KEYS.personal(user?.id || ''));

          queryClient.setQueryData<FoodItem[]>(KEYS.personal(user?.id || ''), (old) => {
              return old ? old.filter(item => item.id !== id) : [];
          });

          return { previousItems };
      },
      onError: (err, id, context) => {
          if (context?.previousItems) {
              queryClient.setQueryData(KEYS.personal(user?.id || ''), context.previousItems);
          }
      },
      onSettled: () => {
          queryClient.invalidateQueries({ queryKey: KEYS.personal(user?.id || '') });
          if (householdId) queryClient.invalidateQueries({ queryKey: KEYS.family(householdId) });
      }
  });

  const bulkSaveMutation = useMutation({
      mutationFn: async (items: (Omit<FoodItem, 'id' | 'user_id' | 'created_at'>)[]) => {
          if (!user) throw new Error("No user");
          return await foodItemService.createFoodItemsBulk(items, user.id);
      },
      onSuccess: () => {
          queryClient.invalidateQueries({ queryKey: KEYS.personal(user?.id || '') });
          if (householdId) queryClient.invalidateQueries({ queryKey: KEYS.family(householdId) });
      }
  });

  // Wrapper functions to match old interface
  const saveItem = useCallback((itemData: any, existingId?: string) => saveMutation.mutateAsync({ itemData, existingId }).then(() => true).catch(() => false), [saveMutation]);
  const deleteItem = useCallback((id: string) => deleteMutation.mutateAsync(id), [deleteMutation]);
  const saveItemsBulk = useCallback((items: any[]) => bulkSaveMutation.mutateAsync(items).then(() => true).catch(() => false), [bulkSaveMutation]);
  const updateInventory = useCallback((id: string, quantity: number) => inventoryMutation.mutate({ id, quantity }), [inventoryMutation]);

  const refreshData = useCallback(() => {
      queryClient.invalidateQueries({ queryKey: KEYS.personal(user?.id || '') });
      if(householdId) queryClient.invalidateQueries({ queryKey: KEYS.family(householdId) });
  }, [queryClient, user, householdId]);

  return {
    foodItems,
    familyFoodItems,
    isLoading: isLoadingPersonal || isLoadingFamily,
    error: errorPersonal ? (errorPersonal as Error).message : null,
    saveItem,
    saveItemsBulk,
    deleteItem,
    updateInventory,
    refreshData
  };
};

