interface SettingsModalProps {
  onClose: () => void;
  household: Household | null;
  householdMembers: UserProfile[];
  onHouseholdCreate: (name: string) => Promise<void>;
  onHouseholdLeave: () => Promise<void>;
  onHouseholdDelete: () => Promise<void>;
