    if (aiSearchResults.ids) {
      const idSet = new Set(aiSearchResults.ids);
      items = items.filter(item => idSet.has(item.id));
    }

    const lowerCaseSearchTerm = searchTerm.toLowerCase();

    items = items
      .filter(item => typeFilter === 'all' || item.itemType === typeFilter)
      .filter(item => {
        if (ownerFilter === 'mine') return item.user_id === user?.id; 
        if (ownerFilter === 'family') return item.isFamilyFavorite; 
        return true; 
      })
      .filter(item => {
        if (ratingFilter === 'all') return true;
        if (ratingFilter === 'liked') return item.rating >= 4;
        if (ratingFilter === 'disliked') return item.rating <= 2 && item.rating > 0;
        return true;
      })
      .filter(item =>  !searchTerm.trim() ? true : (
          item.name.toLowerCase().includes(lowerCaseSearchTerm) ||
          item.notes?.toLowerCase().includes(lowerCaseSearchTerm) ||
          item.tags?.join(' ').toLowerCase().includes(lowerCaseSearchTerm) ||
          (item.itemType === 'dish' && (
              item.restaurantName?.toLowerCase().includes(lowerCaseSearchTerm) ||
              item.cuisineType?.toLowerCase().includes(lowerCaseSearchTerm)
          ))
        )
      );

    return [...items].sort((a, b) => {
      switch (sortBy) {
        case 'date_asc': return new Date(a.created_at).getTime() - new Date(b.created_at).getTime();
        case 'rating_desc': return b.rating - a.rating;
        case 'rating_asc': return a.rating - b.rating;
        case 'name_asc': return a.name.localeCompare(b.name);
        case 'name_desc': return b.name.localeCompare(a.name);
        case 'date_desc':
        default: return new Date(b.created_at).getTime() - new Date(b.created_at).getTime();
      }
    });
  }, [allItems, searchTerm, ratingFilter, typeFilter, ownerFilter, sortBy, aiSearchResults.ids, user?.id]);

  const hydratedShoppingList = useMemo((): HydratedShoppingListItem[] => {
      const foodItemMap = new Map(allItems.map(item => [item.id, item]));
      const hydratedItems: HydratedShoppingListItem[] = [];
      for (const sli of shoppingListItems) {
        const foodItemDetails = foodItemMap.get(sli.food_item_id);
        if (foodItemDetails) {
          hydratedItems.push({
            ...(foodItemDetails as FoodItem),
            shoppingListItemId: sli.id,
            checked: sli.checked,
            added_by_user_id: sli.added_by_user_id,
            checked_by_user_id: sli.checked_by_user_id,
            quantity: sli.quantity,
          });
        }
      }
      return hydratedItems;
  }, [allItems, shoppingListItems]);

  // --- Handlers ---

  useEffect(() => {
    const handleOnline = () => setIsOnline(true);
    const handleOffline = () => setIsOnline(false);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
        window.removeEventListener('online', handleOnline);
        window.removeEventListener('offline', handleOffline);
    };
  }, []);

  // Toast Auto-Dismiss
  useEffect(() => {
      if (toastData) {
          const timer = setTimeout(() => {
              setToastData(null);
              // Clear undoable item if toast disappears naturally
              setLastDeletedItem(null); 
          }, 4000);
          return () => clearTimeout(timer);
      }
  }, [toastData]);

  const showToast = (message: string, action?: { label: string; onClick: () => void }) => {
      setToastData({ message, action });
  };

  const handleToggleShoppingList = useCallback((item: FoodItem) => {
      const existingItem = shoppingListItems.find(i => i.food_item_id === item.id);
      if (existingItem) {
          removeItem(existingItem.id);
          triggerHaptic('medium');
          showToast(t('shoppingList.removedToast', { name: item.name }));
      } else {
          addItemToList(item.id, 1);
          triggerHaptic('success');
          showToast(t('shoppingList.addedToast', { name: item.name }));
      }
  }, [shoppingListItems, removeItem, addItemToList, t]);

  const handleToggleFamilyStatus = useCallback(async (item: FoodItem) => {
      if (!user || item.user_id !== user.id) return;

      const newStatus = !item.isFamilyFavorite;

      // Explicitly construct the object to avoid "Spread types" error on 'item'
      const updatePayload = {
          name: item.name,
          rating: item.rating,
          itemType: item.itemType,
          category: item.category,
          isFamilyFavorite: newStatus,
          notes: item.notes,
          image: item.image,
          tags: item.tags,
          nutriScore: item.nutriScore,
          calories: item.calories,
          ingredients: item.ingredients,
          allergens: item.allergens,
          purchaseLocation: item.purchaseLocation,
          restaurantName: item.restaurantName,
          cuisineType: item.cuisineType,
          price: item.price,
          isLactoseFree: item.isLactoseFree,
          isVegan: item.isVegan,
          isGlutenFree: item.isGlutenFree,
      };

      const success = await saveItem(updatePayload, item.id);

      if (success) {
          triggerHaptic('medium');
          showToast(newStatus ? t('toast.familyShared', { name: item.name }) : t('toast.private', { name: item.name }));
      }
  }, [user, saveItem, t]);

  const handleHouseholdCreateWrapper = useCallback(async (name: string) => {
      try {
          await createHousehold(name);
          showToast(t('shoppingList.joinSuccess', { householdName: name }));
      } catch (e) {}
  }, [createHousehold, t]);

  const handleUndoDelete = useCallback(async (item: FoodItem) => {
      // Explicitly construct the object to avoid "Spread types" error on 'item'
      const restorePayload = {
          name: item.name,
          rating: item.rating,
          itemType: item.itemType,
          category: item.category,
          isFamilyFavorite: item.isFamilyFavorite,
          notes: item.notes,
          image: item.image,
          tags: item.tags,
          nutriScore: item.nutriScore,
          calories: item.calories,
          ingredients: item.ingredients,
          allergens: item.allergens,
          purchaseLocation: item.purchaseLocation,
          restaurantName: item.restaurantName,
          cuisineType: item.cuisineType,
          price: item.price,
          isLactoseFree: item.isLactoseFree,
          isVegan: item.isVegan,
          isGlutenFree: item.isGlutenFree,
      };

      const success = await saveItem(restorePayload); 
      if (success) {
          setLastDeletedItem(null);
          setToastData(null); 
          triggerHaptic('success');
      }
  }, [saveItem]);

  const handleDeleteItem = useCallback(async (id: string) => {
      const itemToDelete = allItems.find(i => i.id === id);
      if (itemToDelete) {
          setLastDeletedItem(itemToDelete);
          await deleteItem(id);
          showToast("Eintrag gelöscht.", {
              label: "Rückgängig",
              onClick: () => handleUndoDelete(itemToDelete)
          });
      }
  }, [allItems, deleteItem, handleUndoDelete]);

  const handleConversationalSearch = useCallback(async (query: string) => {
    setAiSearchQuery(query);
    setIsFilterPanelVisible(false);
    setAiSearchResults({ ids: null, error: null, isLoading: true });
    try {
      const resultIds = await geminiService.performConversationalSearch(query, foodItems);
      setAiSearchResults({ ids: resultIds, error: null, isLoading: false });
    } catch (e) {
      console.error(e);
      setAiSearchResults({ ids: null, error: t('conversationalSearch.error'), isLoading: false });
    }
  }, [foodItems, t]);

  const clearAllFilters = useCallback(() => {
    setSearchTerm(''); setRatingFilter('all'); setTypeFilter('all'); setOwnerFilter('all');
    setAiSearchQuery(''); setAiSearchResults({ ids: null, error: null, isLoading: false });
  }, []);

  const handleSmartQuickAdd = useCallback(async (input: string) => {
      if (!user) return;
      setIsSmartAddLoading(true);
      try {
          const parsedItems = await geminiService.parseShoppingList(input);
          let addedCount = 0;
          for (const parsedItem of parsedItems) {
              let match = allItems.find(i => i.name.toLowerCase() === parsedItem.name.toLowerCase());
              let foodItemId = match?.id;
              if (!foodItemId) {
                  const { createFoodItem } = await import('./services/foodItemService');
                  const newItem = await createFoodItem({ name: parsedItem.name, rating: 0, itemType: 'product', category: parsedItem.category, isFamilyFavorite: !!userProfile?.household_id }, user.id);
                  foodItemId = newItem.id;
                  refreshFoodData();
              }
              if (foodItemId) {
                  addItemToList(foodItemId, parsedItem.quantity);
                  addedCount++;
              }
          }
          if (addedCount > 0) {
              triggerHaptic('success');
              showToast(t('shoppingList.addedAnotherToast', { name: `${addedCount} items` }));
          }
      } catch (e) {
          showToast("Could not process list.");
      } finally {
          setIsSmartAddLoading(false);
      }
  }, [user, allItems, userProfile, addItemToList, refreshFoodData, t]);

  // --- Receipt Handlers ---
  const handleReceiptCapture = async (imageDataUrl: string) => {
      setIsReceiptCameraOpen(false);
      setIsProcessingReceipt(true);
      try {
          const contextItems = hydratedShoppingList.filter(i => i.checked).map(i => ({ id: i.id, name: i.name }));
          const analyzed = await geminiService.analyzeReceiptImage(imageDataUrl, contextItems);
          setScannedReceiptData(analyzed);
      } catch (e) {
          showToast("Could not scan receipt.");
      } finally {
          setIsProcessingReceipt(false);
      }
  };

  const handleSaveReceipt = async (data: Omit<Partial<Receipt>, 'items'> & { items: Partial<ReceiptItem>[] }) => {
      if (!user) return;
      try {
          const savedReceipt = await createReceipt(data, user.id, userProfile?.household_id || undefined);
          setScannedReceiptData(null);
          refreshReceipts(); 
          if (savedReceipt && savedReceipt.items && savedReceipt.items.length > 0) {
              setConfirmedReceiptForImport({ receipt: savedReceipt as Receipt, items: savedReceipt.items as ReceiptItem[] });
          } else {
              showToast("Receipt Saved!");
          }
      } catch (e: any) {
          showToast(`Failed to save: ${e.message}`);
      }
  };

  const handleImportReceiptItems = async (selectedItems: Omit<FoodItem, 'id' | 'user_id' | 'created_at'>[]) => {
      if (selectedItems.length > 0) {
          const success = await saveItemsBulk(selectedItems);
          if (success) {
              triggerHaptic('success');
              showToast(`Imported ${selectedItems.length} items.`);
          }
      }
      setConfirmedReceiptForImport(null);
  };

  // --- Early Returns ---
  if (!session) return <Auth />;

  const displayError = foodError || householdError || shoppingListError;

  return (
    <>
      <Routes>
        <Route element={
            <Layout 
                shoppingListCount={shoppingListItems.filter(i => !i.checked).length}
                isOnline={isOnline}
                searchTerm={searchTerm}
                setSearchTerm={setSearchTerm}
                isAnyFilterActive={isAnyFilterActive}
                toggleAllCategories={() => {
                    const cats = new Set<string>();
                    filteredAndSortedItems.forEach(item => cats.add(item.category || 'other'));
                    const allCats = Array.from(cats);
                    if (collapsedCategories.size >= allCats.length) setCollapsedCategories(new Set());
                    else setCollapsedCategories(new Set(allCats));
                }}
                isAllCollapsed={filteredAndSortedItems.length > 0 && collapsedCategories.size > 0} 
                onOpenSettings={() => navigate('/settings')}
                onOpenFilter={() => setIsFilterPanelVisible(true)}
                ownerFilter={ownerFilter} setOwnerFilter={setOwnerFilter}
                aiSearchQuery={aiSearchQuery} clearAiSearch={() => { setAiSearchQuery(''); setAiSearchResults({ ids: null, error: null, isLoading: false }); }}
                typeFilter={typeFilter} setTypeFilter={setTypeFilter}
                ratingFilter={ratingFilter} setRatingFilter={setRatingFilter}
                clearAllFilters={clearAllFilters}
            />
        }>
            {/* INVENTORY (Dashboard) */}
            <Route path="/" element={
                <>
                    {displayError && isOnline && <div className="bg-red-100 text-red-700 px-4 py-3 rounded m-4">{displayError}</div>}

                    {aiSearchResults.ids !== null && (
                        <div className="mb-6 p-4 bg-indigo-50 dark:bg-gray-800 rounded-lg flex items-center justify-between border border-indigo-100">
                            <div><h2 className="text-xl font-bold text-indigo-800 dark:text-indigo-200">{t('conversationalSearch.resultsTitle')}</h2><p className="text-sm italic">"{aiSearchQuery}"</p></div>
                            <button onClick={() => { setAiSearchQuery(''); setAiSearchResults({ ids: null, error: null, isLoading: false }); }} className="text-sm bg-indigo-200 px-3 py-1.5 rounded-full"><XMarkIcon className="w-4 h-4" /> Clear</button>
                        </div>
                    )}
                    {aiSearchResults.error && <p className="text-red-500 text-center">{aiSearchResults.error}</p>}

                    <Dashboard 
                        items={filteredAndSortedItems}
                        isLoading={isFoodLoading}
                        onAddNew={() => navigate('/add', { state: { startMode: 'camera' } })}
                        onEdit={(id) => navigate(`/edit/${id}`)}
                        onDelete={handleDeleteItem} // Use new handle wrapper
                        onViewDetails={(item) => navigate(`/item/${item.id}`)}
                        onAddToShoppingList={handleToggleShoppingList}
                        onToggleFamilyStatus={handleToggleFamilyStatus}
                        shoppingListFoodIds={shoppingListFoodIds}
                        isFiltering={isAnyFilterActive}
                        collapsedCategories={collapsedCategories}
                        // FIX: Explicitly type Set<string> to avoid inference error
                        onToggleCategory={(category) => setCollapsedCategories(prev => { const n = new Set<string>(prev); n.has(category) ? n.delete(category) : n.add(category); return n; })}
                    />

                    <div className="fixed bottom-[calc(5rem+env(safe-area-inset-bottom,0px))] right-6 z-30">
                        <button onClick={() => navigate('/add', { state: { startMode: 'camera' } })} className="bg-indigo-600 hover:bg-indigo-700 text-white font-bold p-4 rounded-full shadow-xl transition-transform transform hover:scale-105 active:scale-95">
                            <CameraIcon className="w-8 h-8" />
                        </button>
                    </div>
                </>
            } />

            {/* SHOPPING LIST */}
            <Route path="/shopping" element={
                <ShoppingListView 
                    allLists={shoppingLists}
                    activeListId={activeShoppingListId}
                    listData={hydratedShoppingList} 
                    household={household}
                    householdMembers={householdMembers}
                    currentUser={user}
                    onRemove={removeItem} 
                    onClear={clearCompleted} 
                    onToggleChecked={toggleChecked} 
                    onSelectList={setActiveShoppingListId}
                    onCreateList={createList}
                    onDeleteList={deleteList}
                    onUpdateQuantity={updateQuantity}
                    onSmartAdd={handleSmartQuickAdd}
                    isSmartAddLoading={isSmartAddLoading}
                />
            } />

            {/* FINANCE */}
            <Route path="/finance" element={
                <FinanceDashboard 
                    monthlyData={getMonthlySpending()}
                    categoryData={getCategoryBreakdown()}
                    totalSpend={0}
                    isLoading={isReceiptsLoading}
                    onScan={() => setIsReceiptCameraOpen(true)}
                />
            } />

            {/* SUB-PAGES */}
            <Route path="/add" element={<ItemFormPage items={allItems} onSave={(data) => saveItem(data)} householdId={userProfile?.household_id || null} />} />
            <Route path="/edit/:id" element={<ItemFormPage items={allItems} onSave={(data) => saveItem(data, data.id)} householdId={userProfile?.household_id || null} />} />
            <Route path="/item/:id" element={<ItemDetailPage items={allItems} currentUser={user} onImageClick={setSelectedImage} />} />
            <Route path="/settings" element={
                <SettingsPage 
                    household={household} 
                    householdMembers={householdMembers} 
                    onHouseholdCreate={handleHouseholdCreateWrapper}
                    onHouseholdLeave={leaveHousehold}
                    onHouseholdDelete={deleteHousehold}
                    error={householdError}
                />
            } />
        </Route>
      </Routes>

      {/* GLOBAL MODALS (Transient State) */}
      {toastData && (
         <div className="fixed bottom-24 left-1/2 -translate-x-1/2 bg-gray-800 dark:bg-gray-200 text-white dark:text-gray-900 text-sm font-semibold py-3 px-5 rounded-full shadow-lg z-50 flex items-center gap-4 animate-slide-up">
            <span>{toastData.message}</span>
            {toastData.action && (
                <button 
                    onClick={toastData.action.onClick} 
                    className="text-indigo-300 dark:text-indigo-600 hover:text-white dark:hover:text-black font-bold uppercase text-xs tracking-wide"
                >
                    {toastData.action.label}
                </button>
            )}
        </div>
      )}

      {isFilterPanelVisible && (
        <FilterPanel 
            onClose={() => setIsFilterPanelVisible(false)}
            searchTerm={searchTerm} setSearchTerm={setSearchTerm}
            typeFilter={typeFilter} setTypeFilter={setTypeFilter}
            ratingFilter={ratingFilter} setRatingFilter={setRatingFilter}
            ownerFilter={ownerFilter} setOwnerFilter={setOwnerFilter}
            sortBy={sortBy} setSortBy={setSortBy}
            onReset={clearAllFilters}
            onAiSearch={handleConversationalSearch}
            isAiSearchLoading={aiSearchResults.isLoading}
        />
      )}

      {selectedImage && <ImageModal imageUrl={selectedImage} onClose={() => setSelectedImage(null)} />}

      {isReceiptCameraOpen && (
          <CameraCapture onCapture={handleReceiptCapture} onClose={() => setIsReceiptCameraOpen(false)} mode="receipt" />
      )}
      {isProcessingReceipt && (
          <div className="fixed inset-0 bg-black/80 flex flex-col items-center justify-center z-50 text-white">
              <SpinnerIcon className="w-12 h-12 text-white mb-4" />
              <p className="text-lg font-bold">Analyzing...</p>
          </div>
      )}
      {scannedReceiptData && (
          <ReceiptReviewModal receiptData={scannedReceiptData} onSave={handleSaveReceipt} onClose={() => setScannedReceiptData(null)} />
      )}
      {confirmedReceiptForImport && (
          <ReceiptToInventoryModal receipt={confirmedReceiptForImport.receipt} items={confirmedReceiptForImport.items} onConfirm={handleImportReceiptItems} onClose={() => setConfirmedReceiptForImport(null)} />
      )}
      <style>{`
        @keyframes slideUp { from { transform: translate(-50%, 20px); opacity: 0; } to { transform: translate(-50%, 0); opacity: 1; } }
        .animate-slide-up { animation: slideUp 0.3s ease-out; }
      `}</style>
    </>
  );
};

import React, { useState } from 'react';
import { Receipt, ReceiptItem, GroceryCategory } from '../../types';
import { XMarkIcon, SpinnerIcon, CategoryProduceIcon, CategoryBakeryIcon, CategoryMeatIcon, CategoryDairyIcon, CategoryPantryIcon, CategoryFrozenIcon, CategorySnacksIcon, CategoryBeveragesIcon, CategoryHouseholdIcon, CategoryPersonalCareIcon, CategoryOtherIcon, CategoryRestaurantIcon, CheckCircleIcon, TrashIcon, PlusCircleIcon } from '../Icons';
import { useTranslation } from '../../i18n/index';

// FIX: Type definition to allow items to be Partial<ReceiptItem>[]
interface ReceiptReviewModalProps {
    receiptData: Omit<Partial<Receipt>, 'items'> & { items: Partial<ReceiptItem>[] };
    onSave: (data: Omit<Partial<Receipt>, 'items'> & { items: Partial<ReceiptItem>[] }) => Promise<void>;
    onClose: () => void;
    isLoading?: boolean;
}

const CategoryIconMap: Record<GroceryCategory, React.FC<{ className?: string }>> = {
    'produce': CategoryProduceIcon,
    'bakery': CategoryBakeryIcon,
    'meat_fish': CategoryMeatIcon,
    'dairy_eggs': CategoryDairyIcon,
    'pantry': CategoryPantryIcon,
    'frozen': CategoryFrozenIcon,
    'snacks': CategorySnacksIcon,
    'beverages': CategoryBeveragesIcon,
    'household': CategoryHouseholdIcon,
    'personal_care': CategoryPersonalCareIcon,
    'restaurant_food': CategoryRestaurantIcon,
    'other': CategoryOtherIcon,
};

const CATEGORIES: GroceryCategory[] = ['produce', 'bakery', 'meat_fish', 'dairy_eggs', 'pantry', 'frozen', 'snacks', 'beverages', 'household', 'personal_care', 'other'];

export const ReceiptReviewModal: React.FC<ReceiptReviewModalProps> = ({ receiptData, onSave, onClose, isLoading }) => {
    const { t } = useTranslation();
    const [data, setData] = useState(receiptData);
    const [isSaving, setIsSaving] = useState(false);

    // Header Updates
    const updateHeader = (key: keyof Receipt, value: any) => {
        setData(prev => ({ ...prev, [key]: value }));
    };

    // Item Updates
    const updateItem = (index: number, field: keyof ReceiptItem, value: any) => {
        const newItems = [...(data.items || [])];
        newItems[index] = { ...newItems[index], [field]: value };
        // Recalculate total if price/qty changes
        if (field === 'price' || field === 'quantity') {
            const p = field === 'price' ? parseFloat(value) || 0 : newItems[index].price || 0;
            const q = field === 'quantity' ? parseFloat(value) || 1 : newItems[index].quantity || 1;
            newItems[index].total_price = p * q;
        }

        // Update header total if items change
        const newTotal = newItems.reduce((sum, item) => sum + ((item.price || 0) * (item.quantity || 1)), 0);
        setData(prev => ({ ...prev, items: newItems, total_amount: parseFloat(newTotal.toFixed(2)) }));
    };

    const deleteItem = (index: number) => {
        const newItems = [...(data.items || [])];
        newItems.splice(index, 1);
        const newTotal = newItems.reduce((sum, item) => sum + ((item.price || 0) * (item.quantity || 1)), 0);
        setData(prev => ({ ...prev, items: newItems, total_amount: parseFloat(newTotal.toFixed(2)) }));
    };

    const addItem = () => {
        const newItem: Partial<ReceiptItem> = {
            raw_name: '',
            price: 0,
            quantity: 1,
            category: 'other'
        };
        setData(prev => ({ ...prev, items: [...(prev.items || []), newItem] }));
    };

    const handleSave = async () => {
        if (!data.merchant_name || !data.total_amount) {
            alert("Merchant and Total are required.");
            return;
        }
        setIsSaving(true);
        await onSave(data);
        setIsSaving(false);
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-80 flex items-center justify-center z-50 p-0 sm:p-4 animate-fade-in">
            <div className="bg-white dark:bg-gray-900 w-full h-full sm:h-[90vh] sm:max-w-2xl sm:rounded-xl shadow-2xl flex flex-col overflow-hidden">

                {/* Header */}
                <div className="p-4 border-b border-gray-200 dark:border-gray-700 flex justify-between items-center bg-gray-50 dark:bg-gray-800/50 pt-safe-top">
                    <h2 className="text-lg font-bold text-gray-900 dark:text-white">Beleg prüfen</h2>
                    <button onClick={onClose} className="p-2 hover:bg-gray-200 dark:hover:bg-gray-700 rounded-full text-gray-500">
                        <XMarkIcon className="w-6 h-6" />
                    </button>
                </div>

                {/* Content */}
                <div className="flex-1 overflow-y-auto p-4 space-y-6">
                    {/* Meta Data Card */}
                    <div className="bg-indigo-50 dark:bg-indigo-900/10 p-4 rounded-xl border border-indigo-100 dark:border-indigo-800/30 grid grid-cols-2 gap-4">
                        <div className="col-span-2">
                            <label className="block text-xs font-bold text-indigo-900 dark:text-indigo-200 uppercase mb-1">Geschäft</label>
                            <input 
                                type="text" 
                                value={data.merchant_name || ''} 
                                onChange={(e) => updateHeader('merchant_name', e.target.value)}
                                className="w-full bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 rounded-lg p-2 text-lg font-bold"
                            />
                        </div>
                        <div>
                            <label className="block text-xs font-bold text-indigo-900 dark:text-indigo-200 uppercase mb-1">Datum</label>
                            <input 
                                type="date" 
                                value={data.date?.split('T')[0] || ''} 
                                onChange={(e) => updateHeader('date', e.target.value)}
                                className="w-full bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 rounded-lg p-2"
                            />
                        </div>
                        <div>
                            <label className="block text-xs font-bold text-indigo-900 dark:text-indigo-200 uppercase mb-1">Gesamt ({data.currency})</label>
                            <input 
                                type="number" 
                                step="0.01" 
                                value={data.total_amount || ''} 
                                onChange={(e) => updateHeader('total_amount', parseFloat(e.target.value))}
                                className="w-full bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 rounded-lg p-2 text-right font-mono"
                            />
                        </div>
                    </div>

                    {/* Items List */}
                    <div className="space-y-3">
                        <div className="flex justify-between items-center px-1">
                            <h3 className="font-bold text-gray-700 dark:text-gray-300">Artikel ({data.items?.length || 0})</h3>
                            <button onClick={addItem} className="text-indigo-600 dark:text-indigo-400 text-sm font-semibold flex items-center gap-1">
                                <PlusCircleIcon className="w-4 h-4" /> Hinzufügen
                            </button>
                        </div>

                        {data.items?.map((item, idx) => {
                            const CatIcon = CategoryIconMap[item.category || 'other'];
                            return (
                                <div key={idx} className="flex items-center gap-2 bg-white dark:bg-gray-800/50 p-2 rounded-lg border border-gray-100 dark:border-gray-700 shadow-sm">
                                    {/* Category Selector (Cycle through or simple dropdown) */}
                                    <div className="relative group shrink-0">
                                        <button className="p-2 bg-gray-100 dark:bg-gray-700 rounded-full text-gray-500">
                                            <CatIcon className="w-5 h-5" />
                                        </button>
                                        {/* Simple hover/focus dropdown for category */}
                                        <select 
                                            className="absolute inset-0 opacity-0 cursor-pointer w-full h-full"
                                            value={item.category || 'other'}
                                            onChange={(e) => updateItem(idx, 'category', e.target.value)}
                                        >
                                            {CATEGORIES.map(cat => (
                                                <option key={cat} value={cat}>{t(`category.${cat}`)}</option>
                                            ))}
                                        </select>
                                    </div>

                                    {/* Name & Qty */}
                                    <div className="flex-1 min-w-0 flex flex-col gap-1">
                                        <input 
                                            type="text" 
                                            value={item.raw_name || ''} 
                                            onChange={(e) => updateItem(idx, 'raw_name', e.target.value)}
                                            className="w-full bg-transparent border-none p-0 text-sm font-medium focus:ring-0 placeholder-gray-400"
                                            placeholder="Artikelname"
                                        />
                                        <div className="flex items-center gap-2 text-xs text-gray-400">
                                            <span>Menge:</span>
                                            <input 
                                                type="number" 
                                                value={item.quantity || 1} 
                                                onChange={(e) => updateItem(idx, 'quantity', parseFloat(e.target.value))}
                                                className="w-12 bg-gray-100 dark:bg-gray-700 rounded px-1 py-0.5 text-center"
                                            />
                                        </div>
                                    </div>

                                    {/* Price & Delete */}
                                    <div className="flex flex-col items-end gap-1">
                                        <input 
                                            type="number" 
                                            step="0.01" 
                                            value={item.price || ''} 
                                            onChange={(e) => updateItem(idx, 'price', parseFloat(e.target.value))}
                                            className="w-20 bg-transparent border-none p-0 text-sm font-bold text-right focus:ring-0"
                                            placeholder="0.00"
                                        />
                                        <button onClick={() => deleteItem(idx)} className="text-red-400 hover:text-red-500 p-1">
                                            <TrashIcon className="w-4 h-4" />
                                        </button>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>

                {/* Footer Actions */}
                <div className="p-4 border-t border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-900 pb-safe-bottom">
                    <button 
                        onClick={handleSave} 
                        disabled={isSaving || isLoading}
                        className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 px-6 rounded-xl shadow-md transition-transform active:scale-95 flex items-center justify-center gap-2 disabled:bg-indigo-400"
                    >
                        {isSaving || isLoading ? <SpinnerIcon className="w-5 h-5" /> : <CheckCircleIcon className="w-5 h-5" />}
                        {isSaving ? "Speichere..." : "Speichern & Analysieren"}
                    </button>
                </div>
            </div>
        </div>
    );
};

import React, { useState, useMemo } from 'react';
import { TrendingUpIcon, TrendingDownIcon, ReceiptPercentIcon, SpinnerIcon, PencilIcon, ChevronLeftIcon, ChevronRightIcon } from '../Icons';
import { Receipt } from '../../types';
import { useTranslation } from '../../i18n/index';
import { ReceiptEditModal } from './ReceiptEditModal';
import { useReceipts } from '../../hooks/useReceipts';
import { useAuth } from '../../contexts/AuthContext';
import { useHousehold } from '../../hooks/useHousehold';

interface FinanceDashboardProps {
    monthlyData: { label: string; value: number; active?: boolean }[];
    categoryData: { label: string; value: number; color: string }[];
    totalSpend: number;
    isLoading: boolean;
    onScan: () => void;
}

// Helper: Is same Month & Year
const isSameMonth = (d1: Date, d2: Date) => {
    return d1.getMonth() === d2.getMonth() && d1.getFullYear() === d2.getFullYear();
};

// Simple SVG Bar Chart Component
const SimpleBarChart: React.FC<{ data: { label: string; value: number; active?: boolean }[] }> = ({ data }) => {
    const maxValue = Math.max(...data.map(d => d.value), 1);

    return (
        <div className="flex items-end justify-between h-48 w-full gap-2 pt-6">
            {data.map((item, idx) => (
                <div key={idx} className="flex flex-col items-center flex-1 h-full group">
                    <div className="relative flex-1 w-full flex items-end justify-center">
                        {/* Tooltip on hover */}
                        <div className="absolute -top-8 bg-gray-800 text-white text-xs px-2 py-1 rounded opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap z-10 pointer-events-none">
                            {item.value.toFixed(2)} €
                        </div>
                        {/* The Bar */}
                        <div 
                            className={`w-full max-w-[20px] rounded-t-md transition-all duration-500 ease-out ${item.active ? 'bg-indigo-500 dark:bg-indigo-400' : 'bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600'}`}
                            style={{ height: `${(item.value / maxValue) * 100}%` }}
                        ></div>
                    </div>
                    <span className={`text-[10px] mt-2 font-medium ${item.active ? 'text-indigo-600 dark:text-indigo-400' : 'text-gray-500 dark:text-gray-400'}`}>{item.label}</span>
                </div>
            ))}
        </div>
    );
};

// Simple SVG Donut Chart
const SimpleDonutChart: React.FC<{ data: { label: string; value: number; color: string }[] }> = ({ data }) => {
    const total = data.reduce((acc, curr) => acc + curr.value, 0);
    let cumulativePercent = 0;

    const getCoordinatesForPercent = (percent: number) => {
        const x = Math.cos(2 * Math.PI * percent);
        const y = Math.sin(2 * Math.PI * percent);
        return [x, y];
    };

    if (total === 0) return (
        <div className="relative w-40 h-40 flex items-center justify-center">
            <div className="w-full h-full rounded-full border-8 border-gray-200 dark:border-gray-700 opacity-30"></div>
            <span className="absolute text-xs text-gray-400">Keine Daten</span>
        </div>
    );

    return (
        <div className="relative w-48 h-48 mx-auto">
            <svg viewBox="-1 -1 2 2" style={{ transform: 'rotate(-90deg)' }} className="w-full h-full">
                {data.map((slice, i) => {
                    const startPercent = cumulativePercent;
                    const slicePercent = slice.value / total;
                    cumulativePercent += slicePercent;
                    const endPercent = cumulativePercent;

                    // If full circle
                    if (slicePercent === 1) {
                        return <circle key={i} cx="0" cy="0" r="0.8" fill="transparent" stroke={slice.color} strokeWidth="0.4" />;
                    }

                    const [startX, startY] = getCoordinatesForPercent(startPercent);
                    const [endX, endY] = getCoordinatesForPercent(endPercent);
                    const largeArcFlag = slicePercent > 0.5 ? 1 : 0;

                    const pathData = [
                        `M ${startX} ${startY}`,
                        `A 1 1 0 ${largeArcFlag} 1 ${endX} ${endY}`,
                        `L 0 0`,
                    ].join(' ');

                    return (
                        <path 
                            key={i} 
                            d={pathData} 
                            fill={slice.color} 
                            className="transition-all hover:opacity-80 cursor-pointer"
                        />
                    );
                })}
                <circle cx="0" cy="0" r="0.6" fill="var(--bg-card)" className="fill-white dark:fill-gray-900" />
            </svg>
            <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                <span className="text-xs text-gray-500 dark:text-gray-400">Total</span>
                <span className="text-lg font-bold text-gray-900 dark:text-white">{total.toFixed(0)}€</span>
            </div>
        </div>
    );
};

export const FinanceDashboard: React.FC<FinanceDashboardProps> = ({ isLoading, onScan }) => {
    const { t, language } = useTranslation();
    const { user } = useAuth();
    const { userProfile } = useHousehold(user);
    const { receipts, updateReceipt, deleteReceipt } = useReceipts(user, userProfile?.household_id);
    const [editingReceipt, setEditingReceipt] = useState<Receipt | null>(null);

    // --- Navigation State ---
    const [selectedDate, setSelectedDate] = useState(new Date());

    const handlePrevMonth = () => {
        setSelectedDate(prev => {
            const d = new Date(prev);
            d.setMonth(d.getMonth() - 1);
            return d;
        });
    };

    const handleNextMonth = () => {
        const today = new Date();
        const nextMonth = new Date(selectedDate);
        nextMonth.setMonth(nextMonth.getMonth() + 1);

        // Prevent going into future
        if (nextMonth.getTime() > today.getTime() && nextMonth.getMonth() > today.getMonth()) return; 

        setSelectedDate(nextMonth);
    };

    const isCurrentMonth = isSameMonth(selectedDate, new Date());

    // --- Dynamic Calculations based on selectedDate ---

    const currentMonthReceipts = useMemo(() => {
        return receipts.filter(r => isSameMonth(new Date(r.date), selectedDate));
    }, [receipts, selectedDate]);

    const totalSpend = useMemo(() => {
        return currentMonthReceipts.reduce((sum, r) => sum + r.total_amount, 0);
    }, [currentMonthReceipts]);

    const previousMonthTotal = useMemo(() => {
        const prevDate = new Date(selectedDate);
        prevDate.setMonth(prevDate.getMonth() - 1);
        return receipts
            .filter(r => isSameMonth(new Date(r.date), prevDate))
            .reduce((sum, r) => sum + r.total_amount, 0);
    }, [receipts, selectedDate]);

    // Calculate Diff %
    const diffPercent = previousMonthTotal > 0 
        ? Math.round(((totalSpend - previousMonthTotal) / previousMonthTotal) * 100) 
        : 0;

    // Charts: History (Last 6 months ENDING at selectedDate)
    const monthlyHistoryData = useMemo(() => {
        const data = [];
        const monthNames = ["Jan", "Feb", "Mär", "Apr", "Mai", "Jun", "Jul", "Aug", "Sep", "Okt", "Nov", "Dez"];
        const enMonthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
        const names = language === 'de' ? monthNames : enMonthNames;

        for (let i = 5; i >= 0; i--) {
            const d = new Date(selectedDate);
            d.setMonth(d.getMonth() - i);

            // Calculate sum for this month
            const sum = receipts
                .filter(r => isSameMonth(new Date(r.date), d))
                .reduce((acc, r) => acc + r.total_amount, 0);

            data.push({
                label: names[d.getMonth()],
                value: sum,
                active: i === 0 // The selected month is active
            });
        }
        return data;
    }, [receipts, selectedDate, language]);

    // Charts: Categories (Only for selected month)
    const categoryBreakdownData = useMemo(() => {
        const catData: Record<string, number> = {};
        currentMonthReceipts.forEach(receipt => {
            if (receipt.items) {
                receipt.items.forEach(item => {
                    const cat = item.category || 'other';
                    const amount = (item.price || 0) * (item.quantity || 1);
                    catData[cat] = (catData[cat] || 0) + amount;
                });
            } else {
                // If no items, put whole receipt in 'other' or a 'uncategorized' bucket?
                // For simplicity, let's ignore uncategorized receipts in the breakdown or map to 'other'
                // Ideally, receipt items should be populated. If not, maybe use a fallback.
            }
        });

        const categoryColors: Record<string, string> = {
            'produce': '#4ade80',
            'bakery': '#fbbf24',
            'meat_fish': '#f87171',
            'dairy_eggs': '#facc15',
            'pantry': '#fb923c',
            'frozen': '#38bdf8',
            'snacks': '#f472b6',
            'beverages': '#60a5fa',
            'household': '#94a3b8',
            'personal_care': '#c084fc',
            'restaurant_food': '#2dd4bf',
            'other': '#9ca3af',
        };

        return Object.entries(catData)
            .map(([cat, value]) => ({
                label: cat,
                value,
                color: categoryColors[cat] || '#ccc'
            }))
            .sort((a, b) => b.value - a.value);
    }, [currentMonthReceipts]);


    if (isLoading && receipts.length === 0) {
        return <div className="flex justify-center py-20"><SpinnerIcon className="w-8 h-8 text-indigo-500"/></div>;
    }

    const monthLabel = selectedDate.toLocaleString(language === 'de' ? 'de-DE' : 'en-US', { month: 'long', year: 'numeric' });

    return (
        <div className="space-y-6 pb-24 animate-fade-in">
            {/* Navigation Header */}
            <div className="flex justify-between items-center bg-white dark:bg-gray-800 p-2 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700">
                <button onClick={handlePrevMonth} className="p-2 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full transition-colors text-gray-600 dark:text-gray-300">
                    <ChevronLeftIcon className="w-5 h-5" />
                </button>
                <h2 className="text-lg font-bold text-gray-900 dark:text-white capitalize transition-all duration-300 key={selectedDate.toString()}">
                    {monthLabel}
                </h2>
                <button 
                    onClick={handleNextMonth} 
                    disabled={isCurrentMonth}
                    className={`p-2 rounded-full transition-colors ${isCurrentMonth ? 'text-gray-300 dark:text-gray-600 cursor-not-allowed' : 'hover:bg-gray-100 dark:hover:bg-gray-700 text-gray-600 dark:text-gray-300'}`}
                >
                    <ChevronRightIcon className="w-5 h-5" />
                </button>
            </div>

            {/* Main KPI Card */}
            <div className="bg-gradient-to-br from-indigo-600 to-purple-700 rounded-2xl p-6 text-white shadow-xl relative overflow-hidden transition-all duration-500">
                <div className="absolute -right-10 -top-10 w-40 h-40 bg-white opacity-10 rounded-full blur-2xl"></div>
                <div className="relative z-10">
                    <p className="text-indigo-100 text-sm font-medium mb-1">Ausgaben im {selectedDate.toLocaleString('default', { month: 'long' })}</p>
                    <h3 className="text-4xl font-extrabold mb-4">{totalSpend.toFixed(2)} €</h3>

                    <div className="flex items-center gap-2">
                        {totalSpend > 0 && previousMonthTotal > 0 && (
                            <div className={`flex items-center gap-1 px-2 py-1 rounded-full text-xs font-bold ${diffPercent <= 0 ? 'bg-green-400/20 text-green-300' : 'bg-red-400/20 text-red-300'}`}>
                                {diffPercent <= 0 ? <TrendingDownIcon className="w-3 h-3" /> : <TrendingUpIcon className="w-3 h-3" />}
                                <span>{Math.abs(diffPercent)}%</span>
                            </div>
                        )}
                        <span className="text-indigo-200 text-xs">
                            {previousMonthTotal > 0 ? "vs. Vormonat" : "kein Vormonatsdaten"}
                        </span>
                    </div>
                </div>
            </div>

            {/* Charts Section */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {/* Spend History */}
                <div className="bg-white dark:bg-gray-800 rounded-xl p-5 shadow-sm border border-gray-100 dark:border-gray-700">
                    <h4 className="font-bold text-gray-700 dark:text-gray-300 mb-4 text-sm">Verlauf (bis {monthLabel})</h4>
                    <SimpleBarChart data={monthlyHistoryData} />
                </div>

                {/* Categories */}
                <div className="bg-white dark:bg-gray-800 rounded-xl p-5 shadow-sm border border-gray-100 dark:border-gray-700">
                    <h4 className="font-bold text-gray-700 dark:text-gray-300 mb-4 text-sm">Kategorien ({monthLabel})</h4>
                    <div className="flex flex-col items-center">
                        <SimpleDonutChart data={categoryBreakdownData} />
                        <div className="mt-6 w-full grid grid-cols-2 gap-2">
                            {categoryBreakdownData.slice(0, 6).map((cat, i) => (
                                <div key={i} className="flex items-center gap-2 text-xs">
                                    <span className="w-2.5 h-2.5 rounded-full shrink-0" style={{ backgroundColor: cat.color }}></span>
                                    <span className="text-gray-600 dark:text-gray-400 truncate flex-1">{t(`category.${cat.label}`)}</span>
                                    <span className="font-semibold text-gray-800 dark:text-gray-200">{cat.value.toFixed(0)}€</span>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </div>

            {/* Recent Transactions List (Filtered by Month) */}
            <div className="bg-white dark:bg-gray-800 rounded-xl shadow-sm border border-gray-100 dark:border-gray-700 overflow-hidden">
                <div className="p-4 border-b border-gray-100 dark:border-gray-700 flex justify-between items-center">
                    <h4 className="font-bold text-gray-700 dark:text-gray-300 text-sm">Umsätze ({monthLabel})</h4>
                </div>
                <div className="divide-y divide-gray-100 dark:divide-gray-700 max-h-64 overflow-y-auto">
                    {currentMonthReceipts.length === 0 ? (
                        <p className="p-8 text-center text-sm text-gray-500">Keine Umsätze in diesem Monat.</p>
                    ) : (
                        currentMonthReceipts.map(r => (
                            <div 
                                key={r.id} 
                                onClick={() => setEditingReceipt(r)}
                                className="flex items-center justify-between p-4 hover:bg-gray-50 dark:hover:bg-gray-700/50 cursor-pointer transition-colors group"
                            >
                                <div className="flex items-center gap-3">
                                    <div className="bg-gray-100 dark:bg-gray-700 p-2 rounded-full text-gray-500 dark:text-gray-400">
                                        <ReceiptPercentIcon className="w-4 h-4" />
                                    </div>
                                    <div>
                                        <p className="font-semibold text-sm text-gray-900 dark:text-white">{r.merchant_name}</p>
                                        <p className="text-xs text-gray-500 dark:text-gray-400">{new Date(r.date).toLocaleDateString()}</p>
                                    </div>
                                </div>
                                <div className="flex items-center gap-3">
                                    <span className="font-bold text-gray-900 dark:text-white">-{r.total_amount.toFixed(2)} {r.currency}</span>
                                    <PencilIcon className="w-4 h-4 text-gray-300 group-hover:text-indigo-500 transition-colors" />
                                </div>
                            </div>
                        ))
                    )}
                </div>
            </div>

            {/* Scan Action Callout */}
            <div className="bg-indigo-50 dark:bg-indigo-900/20 rounded-xl p-4 flex items-center justify-between border border-indigo-100 dark:border-indigo-800/50">
                <div className="flex items-center gap-3">
                    <div className="bg-indigo-100 dark:bg-indigo-800 p-2.5 rounded-full text-indigo-600 dark:text-indigo-300">
                        <ReceiptPercentIcon className="w-6 h-6" />
                    </div>
                    <div>
                        <h4 className="font-bold text-sm text-gray-900 dark:text-white">Neuer Einkauf?</h4>
                        <p className="text-xs text-gray-500 dark:text-gray-400">Scanne deinen Kassenbon für Details.</p>
                    </div>
                </div>
                <button 
                    onClick={onScan}
                    className="bg-indigo-600 hover:bg-indigo-700 text-white text-xs font-bold py-2 px-4 rounded-full transition-colors"
                >
                    Scannen
                </button>
            </div>

            {/* Edit Modal */}
            {editingReceipt && (
                <ReceiptEditModal 
                    receipt={editingReceipt} 
                    // FIX: Wrapped handlers to return Promise<void> matching expected prop type
                    onSave={async (id, updates) => { await updateReceipt(id, updates); }} 
                    onDelete={async (id) => { await deleteReceipt(id); }} 
                    onClose={() => setEditingReceipt(null)} 
                />
            )}
        </div>
    );
};

import { supabase } from './supabaseClient';
import { Receipt, ReceiptItem } from '../types';

// Map AI Output to DB Payload
const mapReceiptToDbPayload = (receipt: Partial<Receipt>, userId: string, householdId?: string) => {
    return {
        uploader_id: userId,
        household_id: householdId || null,
        merchant_name: receipt.merchant_name || 'Unknown Store', // Fallback
        date: receipt.date || new Date().toISOString(),
        total_amount: typeof receipt.total_amount === 'number' ? receipt.total_amount : 0, // Ensure number
        currency: receipt.currency || 'EUR',
        scanned_at: new Date().toISOString(),
        // image_url handled separately after upload
    };
};

export const createReceipt = async (
    // FIX: Use Omit to allow Partial items
    receiptData: Omit<Partial<Receipt>, 'items'> & { items: Partial<ReceiptItem>[] }, 
    userId: string, 
    householdId?: string,
    imageUrl?: string
): Promise<Receipt | null> => {

    // 1. Create Receipt Record
    const receiptPayload = {
        ...mapReceiptToDbPayload(receiptData, userId, householdId),
        image_url: imageUrl
    };

    const { data: receipt, error: receiptError } = await supabase
        .from('receipts')
        .insert(receiptPayload)
        .select()
        .single();

    if (receiptError) {
        console.error("Error saving receipt header:", receiptError);
        throw new Error(`Receipt Header Save Failed: ${receiptError.message}`);
    }

    if (!receipt) return null;

    // 2. Prepare Items with strict sanitization
    // Database strictly expects numbers for price/qty, usually NOT NULL.
    const itemsPayload = receiptData.items.map(item => {
        const safePrice = typeof item.price === 'number' ? item.price : 0;
        const safeQty = typeof item.quantity === 'number' ? item.quantity : 1;

        return {
            receipt_id: receipt.id,
            raw_name: item.raw_name || 'Unknown Item',
            category: item.category || 'other',
            price: safePrice,
            quantity: safeQty,
            total_price: safePrice * safeQty
        };
    });

    // 3. Save Items
    if (itemsPayload.length > 0) {
        const { error: itemsError } = await supabase
            .from('receipt_items')
            .insert(itemsPayload);

        if (itemsError) {
            console.error("Error saving receipt items:", itemsError);
            // We generally don't delete the receipt header if items fail, 
            // but in a strict transaction we would. Supabase client doesn't support easy transactions yet.
            throw new Error(`Receipt Items Save Failed: ${itemsError.message}`);
        }
    }

    return { ...receipt, items: itemsPayload };
};

export const updateReceipt = async (
    receiptId: string, 
    updates: Partial<Receipt>
): Promise<Receipt> => {
    // Only allow updating specific header fields to maintain data integrity
    const safeUpdates = {
        merchant_name: updates.merchant_name,
        date: updates.date,
        total_amount: updates.total_amount,
        currency: updates.currency
    };

    const { data, error } = await supabase
        .from('receipts')
        .update(safeUpdates)
        .eq('id', receiptId)
        .select()
        .single();

    if (error) throw error;
    return data;
};

export const deleteReceipt = async (receiptId: string): Promise<void> => {
    const { error } = await supabase
        .from('receipts')
        .delete()
        .eq('id', receiptId);

    if (error) throw error;
};

export const fetchReceiptsByHousehold = async (householdId: string) => {
    const { data, error } = await supabase
        .from('receipts')
        .select(`
            *,
            items:receipt_items(*)
        `)
        .eq('household_id', householdId)
        .order('date', { ascending: false });

    if (error) throw error;
    return data;
};

export const fetchReceiptsByUser = async (userId: string) => {
    const { data, error } = await supabase
        .from('receipts')
        .select(`
            *,
            items:receipt_items(*)
        `)
        .eq('uploader_id', userId)
        .order('date', { ascending: false });

    if (error) throw error;
    return data;
};
